#include<bits/stdc++.h>
using namespace std;
vector<int> mp[300010];
int f[300010],ans;
void dfs(int x,int fa=-1)
{
    int max1=0,max2=0;
    for(int i:mp[x])
    {
        if(i!=fa)
        {
            dfs(i,x);
            f[x]=max(f[x],f[i]);
            if(f[i]>max1)
            {
                max2=max1;
                max1=f[i];
            }
            else if(f[i]>max2)
            {
                max2=f[i];
            }
        }
    }
    f[x]+=max(0,(int)(mp[x].size())-(fa!=-1)-1)+1;
    ans=max(ans,max1+max2+1+max(0,(int)(mp[x].size())-2));
}
int main()
{
    int n,m;
    scanf("%d%d",&n,&m);
    for(int i=1;i<=m;i++)
    {
        int u,v;
        scanf("%d%d",&u,&v);
        mp[u].push_back(v);
        mp[v].push_back(u);
    }
    dfs(1);
    printf("%d",ans);
    return 0;
}
